#include <vector>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // parallelise over the outermost loop (rows of A / C)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        // pre‑compute pointers for faster indexing
        double* c_row = &C[i][0];
        const double* a_row = &A[i][0];

        // First scale C[i][*] by beta
        for (int j = 0; j < nj; ++j) c_row[j] *= beta;

        // Accumulate alpha * A[i][k] * B[k][j]
        for (int k = 0; k < nk; ++k) {
            double aik = alpha * a_row[k];
            const double* b_row = &B[k][0];
            for (int j = 0; j < nj; ++j)
                c_row[j] += aik * b_row[j];
        }
    }
}
