#include <vector>
#include <cstddef>
#pragma omp parallel for collapse(2) schedule(static)
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Cache the raw pointers for faster access
    std::vector<double*> Arow(m);
    std::vector<double*> Brow(m);
    for (int i = 0; i < m; ++i) {
        Arow[i] = A[i].data();
        Brow[i] = B[i].data();
    }

    for (int i = 0; i < m; ++i) {
        const double* Ai = Arow[i];
        double* Bi = Brow[i];
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            // Accumulate the dot product of the i-th column of A (reversed)
            // and the j-th column of B from rows i+1..m-1
            for (int k = i + 1; k < m; ++k) {
                sum += Arow[k][i] * Brow[k][j];
            }
            Bi[j] = alpha * (Bi[j] + sum);
        }
    }
}
