#include <vector>
#include <omp.h>
#include <algorithm>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    //--- compute column means -------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / n;
    }

    //--- demean the data -------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        const double* mrow = mean.data();
        for (int j = 0; j < m; ++j)
            row[j] -= mrow[j];
    }

    //--- compute covariance matrix (upper triangular, symmetry) ---------------
    const double denom = 1.0 / (n - 1.0);

    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            cov[i][j] = sum * denom;
            cov[j][i] = cov[i][j];
        }
    }
}
