#include <vector>
#include <cstddef>
#include <immintrin.h>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    const double alpha = 0.33333;          // average coefficient
    double *restrict a = A.data();         // raw pointers for speed
    double *restrict b = B.data();

    /* The loop body does not touch the first and last elements,
       so the work can be safely split into independent chunks.
       Two separate parallel loops are used so that the updates to
       A and B do not depend on each other within the same time step. */
    for (int t = 0; t < tsteps; ++t) {
        /* Update B using values from A */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            /* Use a small unrolled SIMD block for vectorisation */
            /* Each iteration processes one double; the compiler will
               generate efficient instructions (e.g. AVX2). */
            b[i] = alpha * (a[i-1] + a[i] + a[i+1]);
        }

        /* Update A using values from B */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = alpha * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
