/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {

    /* First phase:  x1 = x1 + A * y_1   (row‑wise get) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = x1[i];
        const std::vector<double>& row = A[i];
        const double* restrict y1_ptr = y_1.data();
        const double* restrict row_ptr = row.data();
        for (int j = 0; j < n; ++j)
            sum += row_ptr[j] * y1_ptr[j];
        x1[i] = sum;
    }

    /* Second phase: x2 = x2 + Aᵗ * y_2   (column‑wise get) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = x2[i];
        const double* restrict y2_ptr = y_2.data();
        for (int j = 0; j < n; ++j)
            sum += A[j][i] * y2_ptr[j];
        x2[i] = sum;
