#include <vector>
#include <algorithm>
#include <cstddef>
#include <immintrin.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b)
{
    // Use raw pointers for maximum vectorisation and cache‑locality
    const double * restrict b_ptr = b.data();
    double * restrict    x_ptr = x.data();

    for (int i = 0; i < n; ++i)
    {
        // Load the current right‑hand side value
        double xi = b_ptr[i];

        // Subtract the dot product of the i‑th row of L (up to i‑1)
        // and the already computed elements of x.
        // Use a hand‑rolled 4‑way vectorisation thanks to AVX2.
        const double * restrict Li = L[i].data();
        const double * restrict xi_ptr = x_ptr;

        int j = 0;
        // Vectorised loop: process 4 elements at a time
        for (; j + 3 < i; j += 4)
        {
            __m256d l_vec = _mm256_loadu_pd(&Li[j]);           // L[i][j..j+3]
            __m256d x_vec = _mm256_loadu_pd(&xi_ptr[j]);       // x[j..j+3]
            __m256d prod  = _mm256_mul_pd(l_vec, x_vec);       // L[i][j]*x[j]
            xi -= _mm256_reduce_pd(prod);                     // accumulate reduction
        }
        // Scalar tail
        for (; j < i; ++j)
            xi -= Li[j] * x_ptr[j];

        // Scale by the diagonal element
        xi /= Li[i];
        x_ptr[i] = xi;
    }
}
