#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp)
{
    // Reset output vectors
    for (int i = 0; i < n; ++i) y[i] = 0.0;
    for (int i = 0; i < m; ++i) tmp[i] = 0.0;

    // Local thread‑private accumulation array for y
    const int thread_count = omp_get_max_threads();
    std::vector<std::vector<double>> y_local(thread_count, std::vector<double>(n, 0.0));

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::vector<double>& y_thread = y_local[tid];

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            double t = 0.0;
            // First pass: compute tmp[i]
            const std::vector<double>& Ai = A[i];
            for (int j = 0; j < n; ++j) {
                t += Ai[j] * x[j];
            }
            tmp[i] = t;

            // Second pass: accumulate into thread‑local y
            for (int j = 0; j < n; ++j) {
                y_thread[j] += Ai[j] * t;
            }
        }
    }

    // Reduce thread‑local y into the global result
    for (int t = 0; t < thread_count; ++t) {
        const std::vector<double>& y_thread = y_local[t];
        for (int j = 0; j < n; ++j) {
            y[j] += y_thread[j];
        }
    }
}
