```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) {

    /* 1. Update A[i][j] += u1[i] * v1[j] + u2[i] * v2[j]      */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ui1 = u1[i], ui2 = u2[i];
        double *Ai = A[i].data();
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* 2. Accumulate x[i] += beta * A[j][i] * y[j]  (outer loop over i) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        for (int j = 0; j < n; ++j) {
            xi += beta * A[j][i] * y[j];
        }
        x[i] = xi;
    }

    /* 3. Add z to x */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* 4. Update w[i] += alpha * A[i][j] * x[j]  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double *Ai = A[i].data();
        const double xi = x[i];
        double wi = (i < (int)w.size()) ? w[i] : 0.0;  // defensive
        for (int j = 0; j < n; ++j) {
            wi += alpha * Ai[j] * x[j];
        }
        if (i < (int)w.size()) w[i] = wi;
    }
}
```
This version uses OpenMP parallel loops, accesses memory linearly, and avoids repeated index lookups, yielding substantial speed‑ups while retaining identical results.

