#pragma GCC diagnostic push
#pragma GCC diagnostic ignored "-Wunused-but-set-variable"

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    // Assume the inner vectors are of length n.
    // Retrieve raw pointers for the outer vectors to enable efficient
    // pointer arithmetic. The compiler can inline the access.
    std::vector<double*> Aptr(n);
    std::vector<double*> Bptr(n);
    for (int i = 0; i < n; ++i) {
        Aptr[i] = A[i].data();
        Bptr[i] = B[i].data();
    }
    double* xt = x.data();
    double* yt = y.data();
    double* ttmp = tmp.data();

#pragma omp parallel for schedule(static, 64)
    for (int i = 0; i < n; ++i) {
        double sumA = 0.0;
        double sumB = 0.0;
        const double* arow = Aptr[i];
        const double* brow = Bptr[i];

        // Unroll the inner loop to reduce loop overhead
        int j = 0;
        for (; j + 3 < n; j += 4) {
            double x0 = xt[j];
            double x1 = xt[j + 1];
            double x2 = xt[j + 2];
            double x3 = xt[j + 3];

            sumA += arow[j]     * x0 + arow[j + 1] * x1
                  + arow[j + 2] * x2 + arow[j + 3] * x3;
            sumB += brow[j]     * x0 + brow[j + 1] * x1
                  + brow[j + 2] * x2 + brow[j + 3] * x3;
        }
        // Handle the remaining elements
        for (; j < n; ++j) {
            double xv = xt[j];
            sumA += arow[j] * xv;
            sumB += brow[j] * xv;
        }

        ttmp[i] = sumA;
        yt[i]   = alpha * sumA + beta * sumB;
    }
}

