/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {
    //=>  Form  C := alpha*A*A**T + beta*C.
    // A is NxM, C is NxN (lower triangular part used)

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ci  = C[i].data();          // pointer to the ith row of C
        double* Ai  = A[i].data();          // pointer to the ith row of A

        // scale the first i+1 entries of the row
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        // accumulate alpha * A[i][k] * A[j][k] for each k
        for (int k = 0; k < m; ++k) {
            double aik = Ai[k];
            const double* Ak = &A[0][k];    // pointer to column k

            for (int j = 0; j <= i; ++j) {
                Ci[j] += alpha * aik * Ak[j];
            }
        }
    }
}
