/* Helper to get a raw pointer to a 2‑D vector row */
inline double* row_ptr(std::vector<std::vector<double>>& m, std::size_t i) {
    return m[i].data();
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G) {

    /* Matrix multiplication E = A * B  (ni x nj = ni x nk * nk x nj) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* eRow = row_ptr(E, i);
        const double* aRow = row_ptr(A, i);
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k) {
                sum += aRow[k] * B[k][j];
            }
            eRow[j] = sum;
        }
    }

    /* Matrix multiplication F = C * D  (nj x nl = nj x nm * nm x nl) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double* fRow = row_ptr(F, i);
        const double* cRow = row_ptr(C, i);
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nm; ++k) {
                sum += cRow[k] * D[k][j];
            }
            fRow[j] = sum;
        }
    }

    /* Matrix multiplication G = E * F  (ni x nl = ni x nj * nj x nl) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* gRow = row_ptr(G, i);
        const double* eRow = row_ptr(E, i);
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nj; ++k) {
                sum += eRow[k] * F[k][j];
            }
            gRow[j] = sum;
        }
    }
