```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B)
{
    const int stride = n;          // row width
    const double coeff  = 0.2;     // constant factor

    // Pointer to the underlying contiguous memory of each vector
    double* Adata = &A[0][0];
    double* Bdata = &B[0][0];

    /* Pre‑compute the offsets for neighbor access to avoid repeated
       calculations inside the hot loop. */
    const int left   = -1;
    const int right  =  1;
    const int up     = -stride;
    const int down   =  stride;

#if defined(_OPENMP)
    #pragma omp parallel for schedule(static)
#endif
    for (int t = 0; t < tsteps; ++t) {

        /* Stage 1: Update B from A */
#if defined(_OPENMP)
        #pragma omp parallel for collapse(2) schedule(static)
#endif
        for (int i = 1; i < n-1; ++i) {
            for (int j = 1; j < n-1; ++j) {
                const int idx = i*stride + j;
                Bdata[idx] = coeff * (
                    Adata[idx]           // center
                    + Adata[idx+left]    // left
                    + Adata[idx+right]   // right
                    + Adata[idx+down]    // down
                    + Adata[idx+up]      // up
                );
            }
        }

        /* Stage 2: Update A from B */
#if defined(_OPENMP)
        #pragma omp parallel for collapse(2) schedule(static)
#endif
        for (int i = 1; i < n-1; ++i) {
            for (int j = 1; j < n-1; ++j) {
                const int idx = i*stride + j;
                Adata[idx] = coeff * (
                    Bdata[idx]           // center
                    + Bdata[idx+left]    // left
                    + Bdata[idx+right]   // right
                    + Bdata[idx+down]    // down
                    + Bdata[idx+up]      // up
                );
            }
        }
    }
}
