```cpp
#include <vector>
#include <algorithm>
#include <cstdint>
#include <omp.h>

/*  Nussinov RNA secondary structure prediction
 *  Optimised for x86‑64 with GCC‑O2 + OpenMP.
 *  The public interface required by the harness is unchanged.
 */

static inline int match(int b1, int b2) {
    return (b1 + b2) == 3;
}

/* helper to linearise a 2‑D index using row-major order */
static inline constexpr std::size_t idx(std::size_t i, std::size_t j, std::size_t n) noexcept {
    return i * n + j;
}

/* main kernel ----------------------------------------------------------- */
void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {

    /* Linearise the table to avoid vector‑of‑vector indirection */
    std::vector<int> flat_tbl(n * n, 0);

    /* Ensure the original 2‑D table receives the results */
    auto finalize = [&]() {
        for (int i = 0; i < n; ++i)
            for (int j = 0; j < n; ++j)
                table[i][j] = flat_tbl[idx(i, j, n)];
    };

    /* Main DP loops.
     * Process the anti‑diagonals (i + 1 < j) in parallel.
     */
    #pragma omp parallel for schedule(static)
    for (int i = n - 1; i >= 0; --i) {
        for (int j = i + 1; j < n; ++j) {
            int best = flat_tbl[idx(i, j, n)];

            /* Contributions from neighbours */
            if (j - 1 >= 0)
                best = std::max(best, flat_tbl[idx(i, j - 1, n)]);
            if (i + 1 < n)
                best = std::max(best, flat_tbl[idx(i + 1, j, n)]);

            /* Pairing contribution */
            if (j - 1 >= 0 && i + 1 < n) {
                if (i < j - 1)
                    best = std::max(best,
                                    flat_tbl[idx(i + 1, j - 1, n)] + match(seq[i], seq[j]));
                else
                    best = std::max(best,
                                    flat_tbl[idx(i + 1, j - 1, n)]);
            }

            /* Split contributions */
            for (int k = i + 1; k < j; ++k) {
                int cand = flat_tbl[idx(i, k, n)] + flat_tbl[idx(k + 1, j, n)];
                if (cand > best) best = cand;
            }

            flat_tbl[idx(i, j, n)] = best;
        }
    }

    /* copy back to the user’s 2‑D table */
    finalize();
}
