        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / static_cast<double>(n);
    }

    /* ------------------------------------------------------------------
       2. Compute column standard deviations.
       ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        const double mj = mean[j];
        for (int i = 0; i < n; ++i) {
            const double diff = data[i][j] - mj;
            sum += diff * diff;
        }
        double sd = std::sqrt(sum / static_cast<double>(n));
        stddev[j] = (sd <= eps) ? 1.0 : sd;
    }

    /* ------------------------------------------------------------------
       3. Standard‑normalize the data (in‑place).
       ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Local copies to reduce repeated memory traffic
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            const double val  = row[j] - mean[j];
            row[j] = val * inv_sqrt_n / stddev[j];
        }
    }

    /* ------------------------------------------------------------------
       4. Compute the correlation matrix.
       ------------------------------------------------------------------ */
#pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;   // symmetry
        }
    }
    corr[m - 1][m - 1] = 1.0;
}
