/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    // Reserve scratch space for a column of Q if needed (optional)
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        // 1) Compute the norm of column k of A
        double nrm = 0.0;
        #pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double v = A[i][k];
            nrm += v * v;
        }
        R[k][k] = std::sqrt(nrm);

        // 2) Compute column k of Q
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        // 3) Orthogonalisation of remaining columns
        for (int j = k + 1; j < n; ++j) {
            // 3a) Compute R[k][j] = Q[:,k]^T * A[:,j]
            double dot = 0.0;
            #pragma omp parallel for reduction(+:dot) schedule(static)
            for (int i = 0; i < m; ++i) {
                dot += Q[i][k] * A[i][j];
            }
            R[k][j] = dot;

            // 3b) Update A[:,j] = A[:,j] - Q[:,k] * R[k][j]
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * R[k][j];
            }
        }
    }
}
