/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D) {

    // Small tiling factor that fits comfortably in the L1 cache
    constexpr int T = 32;

    /* --------------------------------------------------------------------
       1) Compute tmp = alpha * A * B  (matrix multiplication A[ni×nk] * B[nk×nj])
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int ii = 0; ii < ni; ii += T) {
        for (int jj = 0; jj < nj; jj += T) {
            int iimax = std::min(ii + T, ni);
            int jjmax = std::min(jj + T, nj);
            for (int i = ii; i < iimax; ++i) {
                // Initialise a local buffer for the current block
                double row[T] = {0.0};
                for (int k = 0; k < nk; ++k) {
                    double a = A[i][k] * alpha;
                    const double* brow = B[k].data();
                    for (int jjblock = 0; jjblock < T; ++jjblock) {
                        int j = jj + jjblock;
                        if (j >= jjmax) break;
                        row[jjblock] += a * brow[j];
                    }
                }
                // Store the block to tmp
                double* tmpRow = tmp[i].data();
                for (int jjblock = 0; jjblock < T; ++jjblock) {
                    int j = jj + jjblock;
                    if (j >= jjmax) break;
                    tmpRow[j] = row[jjblock];
                }
            }
        }
    }

    /* --------------------------------------------------------------------
       2) Compute D = beta * D + tmp * C  (matrix multiplication tmp[ni×nj] * C[nj×nl])
       -------------------------------------------------------------------- */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int ii = 0; ii < ni; ii += T) {
        for (int jj = 0; jj < nl; jj += T) {
            int iimax = std::min(ii + T, ni);
            int jjmax = std::min(jj + T, nl);
            for (int i = ii; i < iimax; ++i) {
                double* drow = D[i].data();
                double* tmpRow = tmp[i].data();
                // Scale the target row by beta once
                for (int jjblock = 0; jjblock < T; ++jjblock) {
                    int j = jj + jjblock;
                    if (j >= jjmax) break;
                    drow[j] *= beta;
                }
                // Accumulate the product tmp * C
                for (int k = 0; k < nj; ++k) {
                    double tk = tmpRow[k];
                    const double* crow = C[k].data();
                    for (int jjblock = 0; jjblock < T; ++jjblock) {
                        int j = jj + jjblock;
                        if (j >= jjmax) break;
                        drow[j] += tk * crow[j];
                    }
                }
            }
        }
    }
}
