void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    // In‑place data pointers for speed
    const double* restrict rdat = r.data();
          double* restrict ydat = y.data();

    // Temporary buffer for z; allocated on the heap for large n
    double* restrict z = nullptr;
    if (n > 0) {
        // 64‑byte alignment for better SIMD throughput
        z = static_cast<double*>(std::aligned_alloc(64, n * sizeof(double)));
        if (!z) std::abort();               // fail fast if allocation fails
    }

    ydat[0] = -rdat[0];
    double beta  = 1.0;
    double alpha = -rdat[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        #pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i) {
            sum += rdat[k - i - 1] * ydat[i];
        }

        alpha = -(rdat[k] + sum) / beta;

        // Update y[0..k-1] using temporary buffer z
        for (int i = 0; i < k; ++i) {
            z[i] = ydat[i] + alpha * ydat[k - i - 1];
        }
        // Copy back to y
        for (int i = 0; i < k; ++i) {
            ydat[i] = z[i];
        }
        ydat[k] = alpha;
    }

    std::free(z);
}
