#include <vector>

/* Optimised LU decomposition and solves.
   The function keeps the same behaviour and signature
   while using raw pointers, register variables and
   avoiding bounds checks. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* ---------- LU decomposition ---------- */
    for (int i = 0; i < n; ++i)
    {
        double* Ai = &A[i][0];          /* pointer to row i */

        /* Fill L (strictly lower part) */
        for (int j = 0; j < i; ++j)
        {
            double w = Ai[j];
            double* Aj = &A[j][0];      /* pointer to row j */
            for (int k = 0; k < j; ++k)
                w -= Ai[k] * Aj[k];
            Ai[j] = w / Aj[j];
        }

        /* Fill U (upper part, including the diagonal) */
        for (int j = i; j < n; ++j)
        {
            double w = Ai[j];
            for (int k = 0; k < i; ++k)
                w -= Ai[k] * A[k][j];
            Ai[j] = w;
        }
    }

    /* ---------- Forward substitution  (L * y = b) ---------- */
    for (int i = 0; i < n; ++i)
    {
        double w = b[i];
        double* Ai = &A[i][0];
        for (int j = 0; j < i; ++j)
            w -= Ai[j] * y[j];
        y[i] = w;
    }

    /* ---------- Backward substitution  (U * x = y) ---------- */
    for (int i = n - 1; i >= 0; --i)
    {
        double w = y[i];
        double* Ai = &A[i][0];
        for (int j = i + 1; j < n; ++j)
            w -= Ai[j] * x[j];
        x[i] = w / Ai[i];
    }
}
