/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    // The matrix is stored as a vector of contiguous rows.
    // Using raw pointers for the inner loops reduces indirection.
    for (int i = 0; i < n; ++i) {
        double* row_i = A[i].data();

        // Lower triangle: compute A[i][j] for j < i
        for (int j = 0; j < i; ++j) {
            double sum = row_i[j];
            const double* row_j = A[j].data();

            // vectorised dot product over k < j
            int k = 0;
            // Unroll by 4 for a bit of speed.
            for (; k + 3 < j; k += 4) {
                sum -= row_i[k]     * row_j[k];
                sum -= row_i[k + 1] * row_j[k + 1];
                sum -= row_i[k + 2] * row_j[k + 2];
                sum -= row_i[k + 3] * row_j[k + 3];
            }
            for (; k < j; ++k) {
                sum -= row_i[k] * row_j[k];
            }
            row_i[j] = sum / row_j[j];
        }

        // Diagonal: compute A[i][i]
        double sum = row_i[i];
        for (int k = 0; k < i; ++k) {
            double v = row_i[k];
            sum -= v * v;
        }
        row_i[i] = std::sqrt(sum);
    }
}
