/*
 * Kernel that computes the symmetric rank‑2k update:
 *
 *    C = beta*C + alpha*(A*Bᵀ + B*Aᵀ)
 *
 * where C is assumed lower‑triangular only (elements above the diagonal
 * are never touched).  The input containers are std::vector<std::vector<double>>
 * to match the original API, but the implementation flattens the data
 * during the call to obtain contiguous memory for fast inner loops.
 */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    /* Flatten the 2‑D views into 1‑D arrays for better locality.
     * We do this on the fly to keep the original API untouched. */
    std::vector<double> Cflat(n * n, 0.0);
    std::vector<double> Aflat(n * m, 0.0);
    std::vector<double> Bflat(n * m, 0.0);

    // Copy data into flattened arrays
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            Cflat[i * n + j] = C[i][j];
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            Aflat[i * m + j] = A[i][j];
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            Bflat[i * m + j] = B[i][j];

    /* Cache‑blocking parameters – tuned manually for typical cache sizes
     * on modern x86‑64 systems.  The block size must be a multiple of the
     * CPU cache line size (64 bytes).  64 Bytes can hold 8 doubles, so
     * a block of 64 fits nicely in L1.  We use a simple square block
     * both for rows and columns. */
    constexpr int blk = 64;   // block size for rows/columns of C

    #pragma omp parallel for schedule(static)
    for (int i0 = 0; i0 < n; i0 += blk) {
        int i1 = std::min(i0 + blk, n);
        for (int j0 = 0; j0 <= i0; j0 += blk) {           // only the lower triangle
            int j1 = std::min(j0 + blk, i0 + 1);          // up to i (inclusive)
            for (int i = i0; i < i1; ++i) {
                double* Ci = &Cflat[i * n];
                // First the beta scaling on the lower triangle of row i
                for (int j = j0; j < j1; ++j)
                    Ci[j] *= beta;

                // Then the main rank‑2k accumulation
                for (int k = 0; k < m; ++k) {
                    double a_k = Aflat[i * m + k];
                    double b_k = Bflat[i * m + k];
                    for (int j = j0; j < j1; ++j) {
                        double a_jk = Aflat[j * m + k];
                        double b_jk = Bflat[j * m + k];
                        Ci[j] += alpha * (a_jk * b_k + b_jk * a_k);
                    }
                }
            }
        }
    }

    // Copy the result back into the original 2‑D containers
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            C[i][j] = Cflat[i * n + j];
}
