/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A)
{
    // Flatten the 2‑D vector to a 1‑D array for contiguous memory access.
    const int sz = n * n;
    std::vector<double> flat(sz);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[i * n + j] = A[i][j];

    const double inv9 = 1.0 / 9.0;

    for (int t = 0; t < tsteps; ++t) {
#pragma omp parallel for schedule(static)
        for (int i = 1; i <= n - 2; ++i) {
            int base   = i * n;
            int up     = (i - 1) * n;
            int down   = (i + 1) * n;
            int idx    = base + 1;          // first j inside loop
            int up_j   = up + 0;            // up[j-1] specifically
            int down_j = down + 0;          // down[j-1] specifically

            for (int j = 1; j <= n - 2; ++j, ++idx, ++up_j, ++down_j) {
                // Using the flattened indices to compute the Neumann stencil.
                flat[idx] = (flat[up_j - 1] + flat[up_j] + flat[up_j + 1] +
                             flat[idx - 1] + flat[idx] + flat[idx + 1] +
                             flat[down_j - 1] + flat[down_j] + flat[down_j + 1]) * inv9;
            }
        }
    }

    // Copy the result back into the original 2‑D vector.
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = flat[i * n + j];
}
