#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    const double coef = 0.125;          // 1/8
    const double coeff2 = 2.0 * coef;   // 1/4

    for (int t = 1; t <= tsteps; ++t) {
        /* First half-step: compute B from A */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
            for (int j = 1; j < n - 1; ++j)
                for (int k = 1; k < n - 1; ++k) {
                    double center = A[i][j][k];
                    double val = 0.0;

                    /* X-direction */
                    val += coef * (A[i + 1][j][k] - coeff2 * center + A[i - 1][j][k]);

                    /* Y-direction */
                    val += coef * (A[i][j + 1][k] - coeff2 * center + A[i][j - 1][k]);

                    /* Z-direction */
                    val += coef * (A[i][j][k + 1] - coeff2 * center + A[i][j][k - 1]);

                    /* Add the center term */
                    val += center;

                    B[i][j][k] = val;
                }

        /* Second half-step: compute A from B */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
            for (int j = 1; j < n - 1; ++j)
                for (int k = 1; k < n - 1; ++k) {
                    double center = B[i][j][k];
                    double val = 0.0;

                    /* X-direction */
                    val += coef * (B[i + 1][j][k] - coeff2 * center + B[i - 1][j][k]);

                    /* Y-direction */
                    val += coef * (B[i][j + 1][k] - coeff2 * center + B[i][j - 1][k]);

                    /* Z-direction */
                    val += coef * (B[i][j][k + 1] - coeff2 * center + B[i][j][k - 1]);

                    /* Add the center term */
                    val += center;

                    A[i][j][k] = val;
                }
    }
}
