#include <vector>
#include <numeric>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {

    // ------------------------------------------------------------------
    // 1. Compute sum of p[0..m-1] – constant part of q
    // ------------------------------------------------------------------
    double sum_p = std::accumulate(p.begin(), p.end(), 0.0);

    // ------------------------------------------------------------------
    // 2. Compute per‑row sums of A (row_sum[i] = Σ_j A[i][j]) and
    //    set q[i] = row_sum[i] + sum_p
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double row_sum = 0.0;
        const double* row = A[i].data();
        for (int j = 0; j < m; ++j) {
            row_sum += row[j];
        }
        q[i] = row_sum + sum_p;
    }

    // ------------------------------------------------------------------
    // 3. Compute s = Aᵀ · r  (s[j] = Σ_i r[i] * A[i][j])
    //    Use OpenMP array reduction (supported by GCC ≥ 9.1)
    // ------------------------------------------------------------------
    #pragma omp parallel for schedule(static) reduction(+:s[:m])
    for (int i = 0; i < n; ++i) {
        double ri = r[i];
        const double* row = A[i].data();
        for (int j = 0; j < m; ++j) {
            s[j] += ri * row[j];
        }
    }
}
