```cpp
#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised implementation of the Deriche kernel.
   The function signature is kept identical to the original harness. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* -------------------------------------------------------------
       Pre‑compute constants that are the same for the whole image.
       ------------------------------------------------------------- */
    const float alpha_f  = static_cast<float>(alpha);
    const float eA       = std::exp(-alpha_f);
    const float e2A      = eA * eA;
    const float k_num    = 1.0f - eA * (1.0f - eA);
    const float k_den    = 1.0f + 2.0f * alpha_f * eA - e2A;
    const float k        = k_num / k_den;

    /* Filter coefficients (a1 … a8, b1 … b2, c1 = c2 = 1.0) */
    const float a1 = k;
    const float a2 = k * eA * (alpha_f - 1.0f);
    const float a3 = k * eA * (alpha_f + 1.0f);
    const float a4 = -k * e2A;
    const float a5 = k;
    const float a6 = k * eA * (alpha_f - 1.0f);
    const float a7 = k * eA * (alpha_f + 1.0f);
    const float a8 = -k * e2A;

    const float b1 = std::pow(2.0f, -alpha_f);
    const float b2 = -e2A;
    const float c  = 1.0f;   // c1 and c2 are both 1

    /* -------------------------------------------------------------
       1. Forward horizontal pass – compute y1.
       ------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        auto* in  = imgIn[i].data();
        auto* out = y1[i].data();

        for (int j = 0; j < h; ++j) {
            const float x = in[j];
            const float val = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            out[j] = val;
            xm1 = x;
            ym2 = ym1;
            ym1 = val;
        }
    }

    /* -------------------------------------------------------------
       2. Backward horizontal pass – compute y2.
       ------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        auto* out = y2[i].data();
        auto* in  = imgIn[i].data();

        for (int jj = h-1; jj >= 0; --jj) {
            const float x = in[jj];
            const float val = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            out[jj] = val;
            xp2 = xp1;
            xp1 = x;
            yp2 = yp1;
            yp1 = val;
        }
    }

    /* -------------------------------------------------------------
       3. First vertical pass – add horizontal results to imgOut.
       ------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        auto* y1p  = y1[i].data();
        auto* y2p  = y2[i].data();
        auto* outp = imgOut[i].data();

        for (int j = 0; j < h; ++j) {
            outp[j] = c * (y1p[j] + y2p[j]);
        }
    }

    /* -------------------------------------------------------------
       4. Forward vertical pass – compute y1 from imgOut.
       ------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            float x = imgOut[i][j];
            float val = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = val;
            tm1 = x;
            ym2 = ym1;
            ym1 = val;
        }
    }

    /* -------------------------------------------------------------
       5. Backward vertical pass – compute y2 from imgOut.
       ------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int ii = w-1; ii >= 0; --ii) {
            float x = imgOut[ii][j];
            float val = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[ii][j] = val;
            tp2 = tp1;
            tp1 = x;
            yp2 = yp1;
            yp1 = val;
        }
    }

    /* -------------------------------------------------------------
       6. Final summation – produce the output image.
       ------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c * (y1[i][j] + y2[i][j]);
        }
    }
}
